反调试技术是为了防止调试器对程序进行调试和逆向工程。在 Linux 环境中，反调试技术主要利用系统调用、信号处理以及特殊的汇编指令来实现。
接下来我们介绍一下 Linux 下常见的反调试技术。
利用getppid在Linux上要跟踪一个程序，必须是它的父进程才能做到，因此，如果一个程序的父进程不是意料之中的bash等（而是gdb，strace之类的），那就说明它被跟踪。
只能检测到gdb调试
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;#include &lt;fcntl.h&gt;#include &lt;string.h&gt;int get_name_by_pid(pid_t pid, char *name) &#123;    int fd;    char buf[1024] = &#123;0&#125;;    snprintf(buf, sizeof(buf), &quot;/proc/%d/cmdline&quot;, pid);        if ((fd = open(buf, O_RDONLY)) == -1) &#123;        return -1;    &#125;    ssize_t bytesRead = read(fd, buf, sizeof(buf) - 1);    close(fd);  // Close file descriptor    if (bytesRead &lt; 0) &#123;        return -1; // Handle read error    &#125;        buf[bytesRead] = &#x27;\0&#x27;; // Ensure null-terminated    strncpy(name, buf, 1023);    name[1023] = &#x27;\0&#x27;; // Ensure null-terminated    return 0;&#125;int main(int argc, char *argv[]) &#123;    char name[1024];    pid_t ppid = getppid();    if (get_name_by_pid(ppid, name) != 0) &#123;        perror(&quot;Failed to get process name&quot;);        return EXIT_FAILURE;    &#125;    if (strcmp(name, &quot;bash&quot;) == 0 || strcmp(name, &quot;init&quot;) == 0) &#123;        printf(&quot;OK!\n&quot;);    &#125; else if (strcmp(name, &quot;gdb&quot;) == 0 ||               strcmp(name, &quot;strace&quot;) == 0 ||               strcmp(name, &quot;ltrace&quot;) == 0) &#123;        printf(&quot;Traced!\n&quot;);    &#125; else &#123;        printf(&quot;Unknown traced\n&quot;);    &#125;    return EXIT_SUCCESS;&#125;

利用session id不论程序是否被调试器跟踪，session id是不变的，而ppid会变。
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;int main()&#123;  if(getsid(getpid())!=getppid())&#123;    puts(&quot;debugging&quot;);    exit(0);  &#125;  puts(&quot;not debugging&quot;);  return 0;&#125;


ptrace系统调用一个进程只能被一个进程ptrace，如果你自己调用ptarace，这样其它程序就无法通过ptrace调试（或者向你的程序进程注入代码）
如果进程已经被调试器跟踪了还再调用ptrace就不会成功。
ptrace的处理要么就是让它不执行，要么就是直接将其nop掉。
使用ptrace可以检测是否有其他进程在调试当前进程。具体方法是尝试用ptrace附加到自身，如果成功则说明没有被调试。
   #include &lt;sys/ptrace.h&gt;#include &lt;unistd.h&gt;#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;int main(int argc, char *argv[])&#123;  if(ptrace(PTRACE_TRACEME,0,1,0)==-1)&#123;    printf(&quot;debugger\n&quot;);    exit(0);  &#125;  printf(&quot;No debugger\n&quot;);  return 0;&#125;

检测父进程只能检测到gdb
通过读取父进程的命令行信息，检测当前程序是否在调试器下运行。
#include &lt;stdio.h&gt;#include &lt;string.h&gt;int main(int argc, char *argv[]) &#123;   char buf1[0x20], buf2[0x100];   FILE* fp;   snprintf(buf1, 24, &quot;/proc/%d/cmdline&quot;, getppid());   fp = fopen(buf1, &quot;r&quot;);   fgets(buf2, 0x100, fp);   fclose(fp);   if(!strcmp(buf2, &quot;gdb&quot;) || !strcmp(buf2, &quot;strace&quot;)||!strcmp(buf2, &quot;ltrace&quot;))   &#123;       printf(&quot;Debugger detected&quot;);       return 1;   &#125;     printf(&quot;All good&quot;);   return 0;&#125;


检测进程运行状态Linux在/proc/self/status中保存了进程的状态信息。通过检查TracerPid字段，可以判断当前进程是否被调试器控制。如果TracerPid不为0，则说明该进程正在被调试。
#include &lt;stdio.h&gt;#include &lt;string.h&gt;int is_debugged() &#123;	//打开一个文件，该文件包含当前进程的状态信息    FILE *status = fopen(&quot;/proc/self/status&quot;, &quot;r&quot;);    //如果文件打开失败，则未检测到调试器    if (status == NULL) return 0;	//读取文件内容    char line[256];    while (fgets(line, sizeof(line), status)) &#123;	    //查找TracerPid行        if (strncmp(line, &quot;TracerPid:&quot;, 10) == 0) &#123;            fclose(status);            //检查TracerPid的值            //获取TracerPid后面的数字部分，并检查它是否大于0.            //如果大于0则表示有进程在跟踪当前进程            return atoi(line + 10) &gt; 0;        &#125;    &#125;    fclose(status);    return 0;&#125;int main() &#123;    if (is_debugged()) &#123;        printf(&quot;Debugger\n&quot;);    &#125; else &#123;        printf(&quot;No debugger\n&quot;);    &#125;    return 0;&#125;

利用环境变量只能检测到gdb
在Linux中，bash有一个环境变量叫$_，它保存的是上一个执行的命令的最后一个参数。如果在被跟踪调试的状态下，这个变量的值会发送变化。
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;// 检测是否被调试void is_debugging(char *program_path) &#123;    // 获取环境变量 &quot;_&quot;    const char *env_path = getenv(&quot;_&quot;);        printf(&quot;Environment Path: %s\n&quot;, env_path);    printf(&quot;Program Path: %s\n&quot;, program_path);    // 如果环境变量与程序路径不一致，判断为被调试    if (strcmp(program_path, env_path) != 0) &#123;        printf(&quot;No debugging detected.\n&quot;);    &#125; else &#123;        printf(&quot;Debugging detected!\n&quot;);        exit(0);    &#125;&#125;int main(int argc, char *argv[]) &#123;    if (argc &lt; 1) &#123;        fprintf(stderr, &quot;Error: Invalid arguments\n&quot;);        exit(0);    &#125;    // 检测是否被调试    is_debugging(argv[0]);    return 0;&#125;

信号处理只能检测到gdb
#include &lt;stdio.h&gt;#include &lt;signal.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;#include &lt;sys/ptrace.h&gt;// 信号处理函数void handle_signal(int sig) &#123;    if (sig == SIGTRAP) &#123;        printf(&quot;Debugger detected via SIGTRAP!\n&quot;);        exit(1); // 退出程序    &#125; else &#123;        printf(&quot;Received signal: %d\n&quot;, sig);    &#125;&#125;int main() &#123;    // 设置信号处理函数    signal(SIGTRAP, handle_signal);        // 使用 ptrace 检测调试器    if (ptrace(PTRACE_TRACEME, 0, NULL, NULL) == -1) &#123;        printf(&quot;Debugger detected via ptrace!\n&quot;);        exit(1);    &#125;    // 触发 SIGTRAP 信号    raise(SIGTRAP);    printf(&quot;No debugger detected\n&quot;);    return 0;&#125;

使用fork和exec仅适用于gdb
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;#include &lt;sys/wait.h&gt;#include &lt;sys/ptrace.h&gt;void anti_debug() &#123;    pid_t pid = fork();    if (pid == -1) &#123;        // fork失败        perror(&quot;fork failed&quot;);        exit(1);    &#125;    if (pid == 0) &#123;        // 子进程尝试调用ptrace，检查是否被调试        if (ptrace(PTRACE_TRACEME, 0, NULL, NULL) == -1) &#123;            // 调试器检测            printf(&quot;Debugger detected!\n&quot;);            exit(1);        &#125;        // 使用exec执行目标程序        execl(&quot;/bin/ls&quot;, &quot;ls&quot;, NULL); // 目标程序可以替换成实际应用程序    &#125; else &#123;        // 父进程等待子进程        int status;        waitpid(pid, &amp;status, 0);        if (WIFEXITED(status) &amp;&amp; WEXITSTATUS(status) == 1) &#123;            // 子进程检测到调试器            printf(&quot;Debugging detected by child process!\n&quot;);            exit(1);        &#125; else &#123;            // 子进程没有检测到调试器            printf(&quot;No debugger detected.\n&quot;);        &#125;    &#125;&#125;int main() &#123;    anti_debug();    return 0;&#125;

检测堆的相对位置仅适用于gdb
#define _DEFAULT_SOURCE#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;#include &lt;string.h&gt;#define RESULT_YES 1#define RESULT_NO 0static int detect(void)&#123;    // 使用静态变量来探测堆的位置    static unsigned char bss;    unsigned char *probe = malloc(0x10); // 在堆上分配内存    // 检查堆的位置相对于 BSS 段    if (probe - &amp;bss &lt; 0x20000) &#123;        // 堆相对于 BSS 段的位置过近，可能被调试器干扰        free(probe); // 释放分配的内存        return RESULT_YES;    &#125; else &#123;        free(probe); // 释放分配的内存        return RESULT_NO;    &#125;&#125;static int cleanup(void)&#123;    // 不需要进行任何清理    return 0;&#125;int main(void) &#123;    // 调测检测    if (detect() == RESULT_YES) &#123;        printf(&quot;Debugger detected: Heap is too close to BSS.\n&quot;);        exit(EXIT_FAILURE);    &#125;    printf(&quot;No debugger detected.\n&quot;);    return 0;&#125;



检测ASLR是否启用仅适用于gdb


检测vdso仅适用于gdb
#define _DEFAULT_SOURCE#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;sys/auxv.h&gt;#include &lt;string.h&gt;#include &lt;unistd.h&gt;#define RESULT_YES 1#define RESULT_NO 0#define RESULT_UNK -1static int is_aslr_enabled(void) &#123;    // 检查 ASLR 是否启用    return (getauxval(AT_RANDOM) != 0) ? RESULT_YES : RESULT_NO;&#125;static int check_vdso(void) &#123;    unsigned long tos;    unsigned long vdso = getauxval(AT_SYSINFO_EHDR);    // 检查 VDSO    if (!vdso) &#123;        return RESULT_UNK; // VDSO 不可用    &#125;    if (is_aslr_enabled() == RESULT_NO) &#123;        return RESULT_UNK; // ASLR 不可用    &#125;    // 检查堆栈顶地址是否高于 VDSO    if ((unsigned long)&amp;tos &gt; vdso) &#123;        return RESULT_YES; // VDSO 被篡改或调试    &#125;    return RESULT_NO; // 正常状态&#125;int main(void) &#123;    if (check_vdso() == RESULT_YES) &#123;        printf(&quot;Debugger detected: VDSO is compromised or debugging is present.\n&quot;);        exit(EXIT_FAILURE);    &#125;    printf(&quot;No debugger detected.\n&quot;);    return 0;&#125;

