关于C面向对象编程的研究。
前段时间在知乎上看到一篇文章，一个大佬说面向对象是一种思想，用C也可以写出很好的面向对象的程序。

文章链接： https://www.zhihu.com/question/30567850/answer/2602179225

于是让我产生了一点好奇，所以就研究了一下C如何进行面向对象编程。
通过结构体和函数指针来模拟面向对象编程。
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;// 定义一个结构体，模拟一个类typedef struct Person &#123;    char name[50];    int age;    // 成员函数（通过函数指针实现）    void (*setName)(struct Person*, const char*);    void (*setAge)(struct Person*, int);    void (*display)(const struct Person*);&#125; Person;// 成员函数的实现void setName(Person* p, const char* name) &#123;    strncpy(p-&gt;name, name, sizeof(p-&gt;name) - 1);    p-&gt;name[sizeof(p-&gt;name) - 1] = &#x27;\0&#x27;; // 确保字符串结束符&#125;void setAge(Person* p, int age) &#123;    p-&gt;age = age;&#125;void display(const Person* p) &#123;    printf(&quot;Name: %s\n&quot;, p-&gt;name);    printf(&quot;Age: %d\n&quot;, p-&gt;age);&#125;// 创建一个新的 Person 实例Person* createPerson(const char* name, int age) &#123;    Person* p = (Person*)malloc(sizeof(Person));    if (p != NULL) &#123;        p-&gt;setName = setName;        p-&gt;setAge = setAge;        p-&gt;display = display;        p-&gt;setName(p, name);        p-&gt;setAge(p, age);    &#125;    return p;&#125;// 释放 Person 实例void destroyPerson(Person* p) &#123;    free(p);&#125;int main() &#123;    // 使用模拟的面向对象方式    Person* person = createPerson(&quot;Alice&quot;, 30);    person-&gt;display(person);    // 修改对象的属性    person-&gt;setName(person, &quot;Bob&quot;);    person-&gt;setAge(person, 25);    person-&gt;display(person);    // 清理    destroyPerson(person);    return 0;&#125;
